#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=998244353;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
int n,m,K,v[110],f[110][35][35][35],C[35][35];
inline void Init(int n)
{
	C[0][0]=1;rep(1,n,i)
	{
		C[i][0]=1;rep(1,i,j)
		{
			DN(C[i][j]=C[i-1][j-1]+C[i-1][j]);
		}
	}
}
inline int qpow(int a,int b)
{
	int res(1);
	for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)res=1ll*res*a%Mod;
	return res;
}
int main()
{
	n=read();m=read()+1;K=read();rep(1,m,i)v[i]=read();
	f[0][0][0][0]=1;Init(n);
	rep(0,m-1,i)
	{
		rep(0,n,j)
		{
			rep(0,n,k)
			{
				rep(0,K,l)
				{
					rep(0,n-k,q)
					{
						DN(f[i+1][(q+j)>>1][k+q][l+((q+j)&1)]+=1ll*f[i][j][k][l]*C[n-k][q]%Mod*qpow(v[i+1],q)%Mod);
					}
				}
			}
		}
	}
	int ans=0;
	rep(0,n,j)
	{
		rep(0,K,l)if(l+__builtin_popcount(j)<=K)
		{
			DN(ans+=f[m][j][n][l]);
		}
	}
	printf("%d\n",ans);
}
